const fs = require('fs');
const content = fs.readFileSync('/data/transcripts/onboarding/onboarding_001.txt', 'utf8').replace(/^\uFEFF/, '').trim();
return [{ json: { account_id: 'demo_001', transcript: content, filename: 'onboarding_001.txt' } }];

const raw = $input.first().json.response;
let updates;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON found');
  updates = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{ json: { parse_error: true, error_message: e.message, raw_response: raw } }];
}
return [{ json: { updates, account_id: updates.account_id } }];

const fs = require('fs');
const updates = $input.first().json.updates;
const account_id = $input.first().json.account_id;

// Load existing v1 memo
const v1Path = `/outputs/accounts/${account_id}/v1/account_memo_v1.json`;
let v1Memo = {};
try {
  v1Memo = JSON.parse(fs.readFileSync(v1Path, 'utf8'));
} catch(e) {
  return [{ json: { error: 'v1 memo not found', path: v1Path } }];
}

// Track changes
const changes = [];

function applyUpdate(v1, updates, path = '') {
  for (const key of Object.keys(updates)) {
    const newVal = updates[key];
    const oldVal = v1[key];
    if (newVal === null || newVal === '' || (Array.isArray(newVal) && newVal.length === 0)) continue;
    if (typeof newVal === 'object' && !Array.isArray(newVal)) {
      if (!v1[key]) v1[key] = {};
      applyUpdate(v1[key], newVal, path + key + '.');
    } else {
      if (JSON.stringify(oldVal) !== JSON.stringify(newVal)) {
        changes.push({ field: path + key, from: oldVal, to: newVal });
        v1[key] = newVal;
      }
    }
  }
}

applyUpdate(v1Memo, updates);
v1Memo.version = 'v2';
v1Memo.source = 'onboarding_call';

return [{ json: { v2Memo: v1Memo, changes, account_id } }];

const { spec, v2Memo, changes, account_id } = $input.first().json;
const fs = require('fs');

// Create v2 directory
const dir = `/outputs/accounts/${account_id}/v2`;
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

// Write v2 memo
fs.writeFileSync(`${dir}/account_memo_v2.json`, JSON.stringify(v2Memo, null, 2), 'utf8');

// Write v2 spec
fs.writeFileSync(`${dir}/agent_spec_v2.json`, JSON.stringify(spec, null, 2), 'utf8');

// Write changelog
const changelog = {
  account_id,
  from_version: 'v1',
  to_version: 'v2',
  updated_at: new Date().toISOString(),
  changes
};
fs.writeFileSync(`${dir}/changes.json`, JSON.stringify(changelog, null, 2), 'utf8');

// Also write to /changelog folder
const clDir = '/outputs/changelog';
if (!fs.existsSync(clDir)) fs.mkdirSync(clDir, { recursive: true });
fs.writeFileSync(`${clDir}/${account_id}_changes.json`, JSON.stringify(changelog, null, 2), 'utf8');

return [{ json: { success: true, account_id, files_written: [`${dir}/account_memo_v2.json`, `${dir}/agent_spec_v2.json`, `${dir}/changes.json`], changes_count: changes.length } }];
